meta.script:
// Define Adobe Target Property
var at_property = "beedee45-3f39-f022-9e83-653d86f7267c";  // Workspace Name

! function () {
	window.tt_getCookie = function (t) {
		var e = RegExp(t + "[^;]+").exec(document.cookie);
		return decodeURIComponent(e ? e.toString().replace(/^[^=]+./, "") : "")
	}
	var t = tt_getCookie("MC1"),
		e = tt_getCookie("MSFPC");
	function o(t) {
		return t.split("=")[1].slice(0, 32)
	}
	var n = "";
	if ("" != t) n = o(t);
	else if ("" != e) n = o(e);
	if (n.length > 0) var r = n;
	if (n.length > 0 && at_property != "") {
		window.targetPageParams = function () {
			return {
				"mbox3rdPartyId": r,
				"at_property": at_property
			}
		}
	} else if (at_property != "") {
		window.targetPageParams = function () {
			return {
				"at_property": at_property
			}
		}
	}
}();

// ContentSquare functions
function isEmpty(val) { return (val === undefined || val == null || val.length <= 0) ? true : false; } function key(obj) { return Object.keys(obj) .map(function(k) { return k + "" + obj[k]; }) .join(""); } function distinct(arr) { var result = arr.reduce(function(acc, e) { acc[key(e)] = e; return acc;}, {}); return Object.keys(result) .map(function(k) { return result[k]; }); }

// Adobe Analytics data collection / ContentSquare ttMeta Object **DO NOT ALTER**
var tnt_response = "";

document.addEventListener("at-request-succeeded", function (e) {
	if (e.detail.analyticsDetails != undefined) {

		/*** 1DS ***/
		window.check1DS = function (j) { // function to check either 1DS or JSLL
			if ( (typeof analytics !== 'undefined') && typeof analytics.isInitialized === 'function' && analytics.isInitialized()) { // Check for 1DS
				tnt_response = e.detail;

				//ContentUpdate Event with Target Friendly names
				if (e.detail.responseTokens != undefined) { //checks for friendly name data from response tokens
					console.log("1DS - present with response tokens");

					//ContentUpdate Event with tnta
					analytics.captureContentUpdate(
						{
							actionType: "A",
							behavior: "12",
							content: JSON.stringify({}),
							pageTags: {
								tnta: (tnt_response && tnt_response.analyticsDetails[0] ? tnt_response.analyticsDetails[0].payload.tnta : ''), //a4t data payload
							}
						}
					)

					var tt_activityCount = e.detail.responseTokens.length;
					for (i = 0; i < tt_activityCount; i++) {
						//1DS Content Update
						console.log('1DS - started captureContentCall - i=' + i);
						analytics.captureContentUpdate(
							{
								actionType: "A",
								behavior: "12",
								content: JSON.stringify({}),
								pageTags: {
									tnta: '',  // null out tnta to prevent duplicate A4T hits
									at_activity_name: (tnt_response && tnt_response.responseTokens[i] ? tnt_response.responseTokens[i]["activity.name"] : ''), //friendly name target activity
									at_exp_name: (tnt_response && tnt_response.responseTokens[i] ? tnt_response.responseTokens[i]["experience.name"] : ''), // friendly name target experience
									at_activity_id: (tnt_response && tnt_response.responseTokens[i] ? tnt_response.responseTokens[i]["activity.id"] : ''),
									at_exp_id: (tnt_response && tnt_response.responseTokens[i] ? tnt_response.responseTokens[i]["experience.id"] : '')
								}
							}
						)
					}

					console.log('1DS - completed captureContentCall');
					// ttMETA object set for ContentSquare pickup
					window.ttMETA = typeof(window.ttMETA) != "undefined" ? window.ttMETA : []; var tokens = e.detail.responseTokens; if (isEmpty(tokens)) { return; } var uniqueTokens = distinct(tokens); uniqueTokens.forEach(function(token) { window.ttMETA.push({ 'CampaignName': token["activity.name"], 'CampaignId': token["activity.id"], 'RecipeName': token["experience.name"], 'RecipeId': token["experience.id"], 'OfferId': token["option.id"], 'OfferName': token["option.name"] }); });
				} else {
					console.log("1DS - present, no response tokens");
				}

			} else {
				console.log('1DS - looping 1DS check');
				if(j < 40) {
					j++;
					setTimeout(function(){check1DS(j)}, 250);
					console.log('1DS - looping 1DS check - loop j=' + j);
				}
			}
		};
		check1DS(1);
		/*** /1DS ***/

	}

});

function adobeTargetTracking() {
	var s = document.createElement( 'script' );
	var src = "https://www.microsoft.com/en-us/security/blog/wp-content/plugins/ms-metrics/assets/js/at.2.9.0.js";
	s.setAttribute( 'src', src );
	document.body.appendChild( s );
}

function comscoreTag() {
	const s = document.createElement( 'script' );
	const src = 'https://www.microsoft.com/library/svy/broker.js';
	s.setAttribute( 'src', src );
	s.setAttribute('async', 'true');
	document.head.appendChild( s );
}

var _linkedin_data_partner_id = "7850";
function linkedinTracking(){
	var s = document.getElementsByTagName("script")[0];
	var b = document.createElement("script");
	b.type = "text/javascript";b.async = true;
	b.src = "https://snap.licdn.com/li.lms-analytics/insight.min.js";
	s.parentNode.insertBefore(b, s);
}

function doubleclickTracking() {
	var random = Math.floor(Math.random() * 10000000000);
	var img = document.createElement('img');
	img.src = 'https://googleads.g.doubleclick.net/pagead/viewthroughconversion/862646735/?guid=ON&script=0&random=' + random;
	img.width = 1;
	img.height = 1;
	img.style = 'display:none;';
	document.body.appendChild(img);
}

function microsoftAds() {
	(function(w, d, t, r, u) {
	var f, n, i;
	w[u] = w[u] || [], f = function() {
	var o = {
	ti: "4000034"
	};
	o.q = w[u], w[u] = new UET(o), w[u].push("pageLoad")
	}, n = d.createElement(t), n.src = r, n.async = 1, n.onload = n.onreadystatechange = function() {
	var s = this.readyState;
	s && s !== "loaded" && s !== "complete" || (f(), n.onload = n.onreadystatechange = null) }, i = d.getElementsByTagName(t)[0], i.parentNode.insertBefore(n, i)
	})(window, document, "script", "//bat.bing.com/bat.js", "uetq");
}

function marketoTracking() {
	const s = document.createElement('script');
	s.type = 'text/javascript';
	s.async = true;
	s.src = 'https://munchkin.marketo.net/munchkin.js';
	s.onload = function() {
		const currentDomain = window.location.hostname;
		let isDebugMode = false;

		const munchkinConfig = {
			cookieLifeDays: 365
		};

		// Add staging-specific settings.
		if (
			currentDomain.includes('stage') ||
			currentDomain.includes('azurefd.net') ||
			currentDomain.includes('azurewebsites.net')
		) {
			munchkinConfig.domainLevel = 3;
			isDebugMode = true; // Lower environments.
		}

		// Local debug.
		if (currentDomain.includes('.test')) {
			isDebugMode = true;
		}

		// Initialize Munchkin after the script has loaded.
		Munchkin.init("157-GQE-382", munchkinConfig);

		if (typeof analytics !== 'undefined' && typeof analytics.isInitialized === 'function' && analytics.isInitialized()) {
			const regex = new RegExp(`(^| )_mkto_trk=([^;]+)`)
			const match = document.cookie.match(regex)

			if (!match && isDebugMode) {
				console.log('No Munchkin cookie found - can\'t verify implementation');
			}

			if (match) {
				// Munchkin ID.
				const munchkinId = match[2];

				// Add telemetry initializer to include Munchkin ID in all future events.
				analytics.addTelemetryInitializer(function (envelope) {
					// For web events (pageView, click, etc.).
					if (envelope.data && envelope.data.baseData) {
						if (!envelope.data.baseData.properties) {
							envelope.data.baseData.properties = {};
						}
						envelope.data.baseData.properties.munchKinId = munchkinId;
					}

					// Content update events.
					if (envelope.data && envelope.data.baseData && envelope.data.baseData.pageTags) {
						if (!envelope.data.baseData.pageTags.metaTags) {
							envelope.data.baseData.pageTags.metaTags = {};
						}
						envelope.data.baseData.pageTags.metaTags.munchKinId = munchkinId;
					}

					return true;
				});

				analytics.captureContentUpdate({
					pageTags: {
						metaTags: {
							munchKinId: munchkinId
						}
					}
				});

				if (isDebugMode) {
					console.log('Munchkin ID added to telemetry initializer: ' + munchkinId);
				}
			}
		}
	};

	document.getElementsByTagName('head')[0].appendChild(s);
}

div.script:
const globalPrivacyControlEnabled = navigator.globalPrivacyControl;

const GPC_DataSharingOptIn = (globalPrivacyControlEnabled) ? false : checkThirdPartyAdsOptOutCookie();

if(window.onGPCLoaded) {
    window.onGPCLoaded();
}

function checkThirdPartyAdsOptOutCookie() {
    try {
        const ThirdPartyAdsOptOutCookieName = '3PAdsOptOut';
        var cookieValue = getCookie(ThirdPartyAdsOptOutCookieName);
        return cookieValue != 1;
    } catch {
        return true;
    }
}

function getCookie(cookieName) {
    var cookieValue = document.cookie.match('(^|;)\\s*' + cookieName + '\\s*=\\s*([^;]+)');
    return (cookieValue) ? cookieValue[2] : '';
}

body.script:
let retryCount = 0;
const maxRetries = 50;

// Check if analytics is initialized before using it.
function maybeMetrics3pScripts() {
	// Check if 1DS analytics is initialized.
	if (
		typeof analytics !== 'undefined' &&
		typeof analytics.isInitialized === 'function' &&
		analytics.isInitialized()
	) {
		// 1DS is ready, call the original function.
		Metrics_3P_Scripts();
	} else if (retryCount < maxRetries) {
		retryCount++;
		// If 1DS isn't ready yet, wait and try again.
		setTimeout(maybeMetrics3pScripts, 100);
	} else {
		console.warn('Analytics initialization failed after maximum retries.');
	}
}

function onConsentChanged( categoryPreferences ) {
	maybeMetrics3pScripts();

	// If any categories are disabled, clear all cookies
	if ( ! siteConsent.getConsentFor( WcpConsent.consentCategories.Analytics ) ) {
		Metrics_Clear_Cookies( 'Analytics' );
	}

	if ( ! siteConsent.getConsentFor( WcpConsent.consentCategories.Advertising ) ) {
		Metrics_Clear_Cookies( 'Advertising' );
	}

	if ( ! siteConsent.getConsentFor( WcpConsent.consentCategories.SocialMedia ) ) {
		Metrics_Clear_Cookies( 'SocialMedia' );
	}
}

function Metrics_Clear_Cookies( category ) {
	var all_cookies = document.cookie.split(";");

	// array of cookie names to clear
	const cookie_names = [
		'_clck',
		'_clsk',
		'_fbp',
		'_uetvid',
		'mbox',
		'AnalyticsSyncHistory',
		'bcookie',
		'bscookie',
		'li_sugr',
		'lidc',
		'li_gc',
		'UserMatchHistory',
		'_mkto_trk'
	];

	for ( var i = 0; i < all_cookies.length; i++ ) {
		var cookie_name = all_cookies[i].split("=")[0].trim();
		if ( cookie_names.includes( cookie_name ) ) {
			document.cookie = cookie_name + '=;expires=Thu, 01 Jan 1970 00:00:01 GMT;';
		}
	}
}

function Metrics_3P_Scripts() {
	// if GPC_DataSharingOptIn is set and true set Metrics_3POptIn
	var Metrics_3P_OptIn = false;
	if ( typeof GPC_DataSharingOptIn !== 'undefined' && GPC_DataSharingOptIn ) {
		Metrics_3P_OptIn = true;
	} else {
		Metrics_3P_OptIn = false;
		Metrics_Clear_Cookies();
	}

	if ( siteConsent.getConsentFor( WcpConsent.consentCategories.Analytics ) && Metrics_3P_OptIn ) {
							if ( typeof comscoreTag === "function" ) {
				comscoreTag(); 
			}
							if ( typeof microsoftAds === "function" ) {
				microsoftAds(); 
			}
							if ( typeof marketoTracking === "function" ) {
				marketoTracking(); 
			}

		if ( siteConsent.getConsentFor( WcpConsent.consentCategories.Advertising ) ) {
									if ( typeof adobeTargetTracking === "function" ) {
					adobeTargetTracking(); 
				}
									if ( typeof clarityTracking === "function" ) {
					clarityTracking(); 
				}

			if ( siteConsent.getConsentFor( WcpConsent.consentCategories.SocialMedia ) ) {
											if ( typeof facebookTracking === "function" ) {
						facebookTracking(); 
					}
											if ( typeof linkedinTracking === "function" ) {
						linkedinTracking(); 
					}
									}
		}

		if ( siteConsent.getConsentFor( WcpConsent.consentCategories.SocialMedia ) ) {
							}
	}

	if ( siteConsent.getConsentFor( WcpConsent.consentCategories.Advertising ) && Metrics_3P_OptIn ) {
							if ( typeof doubleclickTracking === "function" ) {
				doubleclickTracking(); 
			}

		if ( siteConsent.getConsentFor( WcpConsent.consentCategories.SocialMedia ) ) {
							}
	}

	if ( siteConsent.getConsentFor( WcpConsent.consentCategories.SocialMedia ) && Metrics_3P_OptIn ) {
					}
}

			window.WcpConsent && WcpConsent.init( "en-US", "ms-cookie-banner", function (err, _siteConsent) {

		if ( ! err ) {
			siteConsent = _siteConsent;  //siteConsent is used to get the current consent

			var consentRequiredElementExists = document.getElementById( "c-uhff-footer_managecookies" ) && siteConsent.isConsentRequired;

			if ( consentRequiredElementExists ) {
				document.getElementById( "c-uhff-footer_managecookies" ).classList.remove("x-hidden");
				document.getElementById( "c-uhff-footer_managecookies" ).onclick = function() {
					siteConsent.manageConsent();
				};
			}

			maybeMetrics3pScripts();

		} else {
			console.log( "Error initializing WcpConsent: " + err );
		}
	}, onConsentChanged );

( function() {
	var skipLinkTarget = document.querySelector( 'main' ),
		sibling,
		skipLinkTargetID,
		skipLink;

	// Early exit if a skip-link target can't be located.
	if ( ! skipLinkTarget ) {
		return;
	}

	/*
	 * Get the site wrapper.
	 * The skip-link will be injected in the beginning of it.
	 */
	sibling = document.querySelector( '.wp-site-blocks' );

	// Early exit if the root element was not found.
	if ( ! sibling ) {
		return;
	}

	// Get the skip-link target's ID, and generate one if it doesn't exist.
	skipLinkTargetID = skipLinkTarget.id;
	if ( ! skipLinkTargetID ) {
		skipLinkTargetID = 'wp--skip-link--target';
		skipLinkTarget.id = skipLinkTargetID;
	}

	// Create the skip link.
	skipLink = document.createElement( 'a' );
	skipLink.classList.add( 'skip-link', 'screen-reader-text' );
	skipLink.href = '#' + skipLinkTargetID;
	skipLink.innerHTML = 'Skip to content';

	// Inject the skip link.
	sibling.parentElement.insertBefore( skipLink, sibling );
}() );

// 1DS initialization.
const analytics = new oneDS.ApplicationInsights();
var config = {
	instrumentationKey: "cb68b8f590184975aa5eb4ed576fb074-e666ac9b-fa31-4339-8b9c-775f4bae31f3-6978",
	cookieCfg: {
		enabled: true,
		domainCookiesEnabled: true,
		domain: ".microsoft.com",
	},
	propertyConfiguration: {
		gpcDataSharingOptIn: ( typeof GPC_DataSharingOptIn !== "undefined" ) ? GPC_DataSharingOptIn : true,
		callback: {
			userConsentDetails: ( typeof siteConsent !== "undefined" ) ? siteConsent.getConsent : WcpConsent.siteConsent
		},
	},
	webAnalyticsConfiguration:{
		coreData: {"pageName":"404","pageType":"404"},
		urlCollectQuery: true,
		urlCollectHash: true,
		autoCapture: {
			scroll: true,
			pageView: true,
			onLoad: true,
			onUnload: true,
			click: true,
			scroll: true,
			resize: true,
			jsError: true
		}
	}
};
// Initialize OneDS SDK
analytics.initialize( config, [] );
